const childWorkflows = ['CWF-410', 'CWF-420', 'CWF-430', 'CWF-440'];
let executionPlan = { workflows_to_execute: childWorkflows, current_index: 0, status: 'PLANNING', asset_assembly_required: true };
return [{ json: { ...$json, execution_plan: executionPlan, pack_orchestration: { started_at: new Date().toISOString(), expected_duration_seconds: 240 } } }];

const childResults = { CWF_410: $json.cwf410_result, CWF_420: $json.cwf420_result, CWF_430: $json.cwf430_result, CWF_440: $json.cwf440_result };
const allHealthy = Object.values(childResults).every(r => r?.status === 'SUCCESS' || r?.status === 'COMPLETED');
const thumbnailsGenerated = $json.cwf410_result?.payload?.thumbnail_variants_count >= 3;
const visualAssetsPlanned = $json.cwf420_result?.payload?.visual_assets_planned === true;
const audioOptimized = $json.cwf430_result?.payload?.audio_optimization_complete === true;
const mediaPackaged = $json.cwf440_result?.payload?.media_package_assembled === true;
const validationOk = allHealthy && thumbnailsGenerated && visualAssetsPlanned && audioOptimized && mediaPackaged;
return [{ json: { ...$json, pack_validation: { child_results_aggregated: childResults, all_children_healthy: allHealthy, thumbnails_generated: thumbnailsGenerated, visual_assets_planned: visualAssetsPlanned, audio_optimized: audioOptimized, media_packaged: mediaPackaged, validation_ok: validationOk, route_to_error: !validationOk } } }];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    ...$json,
    dossier_write: {
      mutation_type: 'namespace_update',
      target: 'dossier.media',
      timestamp: new Date().toISOString(),
      writer_id: 'WF-400',
      pack_context: $json.pack_context,
      child_results: $json.pack_validation.child_results_aggregated,
      audit_entry: 'media-production-pack-completion from WF-400'
    }
  }
}];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    ...$json,
    se_route_runs_write: {
      operation: 'record_pack_execution',
      pack_id: 'WF-400',
      dossier_id: $json.dossier_id,
      child_workflows_executed: ['CWF-410', 'CWF-420', 'CWF-430', 'CWF-440'],
      execution_status: 'COMPLETED',
      media_packaged: $json.pack_validation.media_packaged,
      timestamp: new Date().toISOString()
    }
  }
}];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    workflow_id: 'WF-400',
    execution_status: 'SUCCESS',
    completion_packet: {
      instance_id: 'WF-400-COMP-' + Date.now(),
      artifact_family: 'media_production_result',
      schema_version: '1.0.0',
      producer_workflow: 'WF-400',
      dossier_ref: $json.dossier_id,
      created_at: new Date().toISOString(),
      status: 'CREATED',
      payload: {
        pack_executed: 'WF-400',
        media_packaged: $json.pack_validation.media_packaged,
        next_workflow: 'WF-500',
        child_packets: ['CWF-410_output', 'CWF-420_output', 'CWF-430_output', 'CWF-440_output']
      }
    }
  }
}];

if (!$json.pack_validation.route_to_error) return [];
return [{
  json: {
    workflow_id: 'WF-400',
    routing_decision: 'ERROR',
    route_to_workflow: 'WF-900',
    error_message: 'Pack validation failed or media assembly failed',
    failure_context: $json.pack_validation,
    child_results: $json.pack_validation.child_results_aggregated
  }
}];

const subOutput = $json || {};
let parentCtx = {};
try { parentCtx = $('Execution Planner Node').first().json || {}; } catch(e) {}
const acc = { ...parentCtx };
acc["cwf410_result"] = {
  status: subOutput.execution_status || subOutput.status || 'SUCCESS',
  payload: subOutput.completion_packet || subOutput.payload || subOutput,
  captured_at: new Date().toISOString()
};
return [{ json: acc }];

